#!/usr/bin/env python3
from pathlib import Path
import argparse, json, html, re
ROOT = Path(__file__).resolve().parents[1]
CARD_DATA = ROOT / "data" / "proof-cards" / "proof-cards-v17.json"
CSS = ":root{--pc-navy:#061229;--pc-ink:#0a1630;--pc-muted:#51627c;--pc-gold:#b68a2e;--pc-ivory:#fbf7ef;--pc-line:#eadfca;--pc-shadow:0 26px 80px rgba(5,14,35,.12)}*{box-sizing:border-box}.proof-command-center{background:linear-gradient(180deg,#fbf7ef,#f7efe2);color:var(--pc-ink);padding:88px 0;border-top:1px solid var(--pc-line);border-bottom:1px solid var(--pc-line);font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif}.proof-shell{width:min(1180px,calc(100% - 34px));margin:0 auto}.proof-kicker{font-size:.78rem;text-transform:uppercase;letter-spacing:.18em;color:var(--pc-gold);font-weight:900}.proof-title{font-size:clamp(2.2rem,5vw,5.6rem);line-height:.94;letter-spacing:-.06em;margin:14px 0 18px;color:var(--pc-ink);font-weight:950}.proof-subtitle{font-size:1.12rem;line-height:1.7;max-width:860px;color:var(--pc-muted);margin:0 0 26px}.proof-hero{display:grid;grid-template-columns:minmax(0,1.1fr) minmax(320px,.9fr);gap:24px;align-items:stretch}.proof-panel{border:1px solid var(--pc-line);background:#fff;border-radius:28px;padding:28px;box-shadow:var(--pc-shadow)}.proof-panel.dark{background:linear-gradient(135deg,#061229,#0d2146);color:white;border:0}.proof-panel.dark p{color:#d8e5fa}.proof-card-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px;margin-top:24px}.proof-card-tile{display:flex;flex-direction:column;gap:12px;background:white;border:1px solid var(--pc-line);border-radius:24px;padding:22px;color:var(--pc-ink);box-shadow:0 12px 36px rgba(5,14,35,.08)}.proof-card-tile:hover{text-decoration:none;transform:translateY(-2px);box-shadow:0 20px 54px rgba(5,14,35,.14)}.proof-card-number{display:inline-flex;width:max-content;border:1px solid rgba(182,138,46,.35);background:#fff8e5;color:#8b651e;border-radius:999px;padding:5px 10px;font-size:.75rem;font-weight:900;letter-spacing:.08em}.proof-card-tile h3{margin:0;font-size:1.22rem;line-height:1.18;letter-spacing:-.03em;color:var(--pc-ink)}.proof-card-tile p{margin:0;color:var(--pc-muted);line-height:1.55}.proof-meter{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-top:18px}.proof-metric{background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.18);border-radius:18px;padding:14px}.proof-metric strong{display:block;color:#f0d891;font-size:1.4rem}.proof-cta{display:flex;gap:12px;flex-wrap:wrap;margin-top:22px}.proof-btn{display:inline-flex;align-items:center;justify-content:center;border-radius:999px;padding:12px 18px;font-weight:900;border:1px solid var(--pc-line);background:white;color:var(--pc-ink);text-decoration:none}.proof-btn.primary{background:linear-gradient(135deg,#b68a2e,#e2bd66);color:#081127;border:0}.proof-page{background:#fbf7ef;color:var(--pc-ink);min-height:100vh;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif}.proof-page header{background:#061229;color:white}.proof-page nav{width:min(1180px,calc(100% - 34px));margin:0 auto;padding:16px 0;display:flex;justify-content:space-between;align-items:center;gap:16px}.proof-page nav a{color:white;text-decoration:none;font-weight:800}.proof-main{width:min(1180px,calc(100% - 34px));margin:0 auto;padding:70px 0}.proof-page h1{font-size:clamp(2.2rem,5vw,5.3rem);letter-spacing:-.06em;line-height:.96;margin:14px 0 18px}.proof-page h2{font-size:1.7rem;letter-spacing:-.035em;margin:36px 0 14px}.proof-page p,.proof-page li{font-size:1.02rem;line-height:1.65;color:var(--pc-muted)}.proof-lead{font-size:1.2rem!important;max-width:860px}.proof-section{background:#fff;border:1px solid var(--pc-line);border-radius:26px;padding:28px;margin:22px 0;box-shadow:0 14px 40px rgba(5,14,35,.07)}.proof-table{width:100%;border-collapse:separate;border-spacing:0;overflow:hidden;border:1px solid var(--pc-line);border-radius:18px;background:white}.proof-table th,.proof-table td{padding:14px 16px;text-align:left;border-bottom:1px solid var(--pc-line);vertical-align:top}.proof-table th{background:#f3ead9;color:#7b591c;font-size:.78rem;text-transform:uppercase;letter-spacing:.1em}.proof-table tr:last-child td{border-bottom:0}.proof-warning{background:#fff5e9;border:1px solid #eed5ae;color:#5a4018;border-radius:18px;padding:16px;margin-top:18px}.proof-diagram{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:10px;margin:18px 0}.proof-node{background:linear-gradient(135deg,#fff,#f7efe2);border:1px solid var(--pc-line);border-radius:16px;padding:12px;text-align:center;font-weight:800;color:var(--pc-ink)}.proof-node.accent{background:linear-gradient(135deg,#061229,#132c5d);color:white}.proof-footer{padding:36px 0;color:var(--pc-muted);border-top:1px solid var(--pc-line);text-align:center}@media(max-width:860px){.proof-hero,.proof-card-grid{grid-template-columns:1fr}.proof-meter{grid-template-columns:repeat(2,1fr)}.proof-diagram{grid-template-columns:1fr 1fr}.proof-page h1{font-size:2.5rem}}"
def esc(x): return html.escape(str(x), quote=True)
def slug(c): return f"proof-card-{c['id']}.html"
def load_cards(): return json.loads(CARD_DATA.read_text(encoding="utf-8"))["cards"]
def write_asset(site):
    (site/"assets").mkdir(exist_ok=True)
    (site/"assets"/"proof-cards-v17.css").write_text(CSS, encoding="utf-8")
def tile(c):
    return f"<a class='proof-card-tile' href='{slug(c)}'><span class='proof-card-number'>PROOF CARD {esc(c['id'])}</span><h3>{esc(c['title'])}</h3><p>{esc(c['phase'])}</p><p>{esc(c['incremental'])}</p></a>"
def section(cards):
    return """<!-- GOALOS_PROOF_CARDS_V17_START --><section class='proof-command-center' id='proof-card-command-center'><div class='proof-shell'><div class='proof-kicker'>Canonical main website proof system</div><div class='proof-hero'><div><h2 class='proof-title'>Proof Cards 001-010</h2><p class='proof-subtitle'>GoalOS-native alpha-AGI Ascension turns sovereign corporate work into auditable proof. AGIALPHA coordinates proof-settled missions. Evidence Dockets make claims inspectable. Sovereign RSI reuses only what proved itself.</p><div class='proof-cta'><a class='proof-btn primary' href='proof-cards.html'>View all proof cards</a><a class='proof-btn' href='proof-card-010.html'>Open Proof Card 010</a><a class='proof-btn' href='agialpha-ledger-route.html'>See AGIALPHA route</a><a class='proof-btn' href='sovereign-rsi-control-plane.html'>See RSI control plane</a></div></div><div class='proof-panel dark'><div class='proof-kicker'>Execution moat</div><h3 style='font-size:1.7rem;margin:10px 0;color:#fff'>From proof cards to compounding capability</h3><p>Each proof card is a stable public page connected to the main website root. Each card explains the mission, AGIALPHA use, contract route, Evidence Docket, skills, plans, goals, and scoped RSI upgrade logic.</p><div class='proof-meter'><div class='proof-metric'><strong>10</strong><span>proof cards</span></div><div class='proof-metric'><strong>1</strong><span>canonical root</span></div><div class='proof-metric'><strong>RSI</strong><span>proof-backed</span></div><div class='proof-metric'><strong>AGIALPHA</strong><span>settlement rail</span></div></div></div></div><div class='proof-card-grid'>""" + ''.join(tile(c) for c in cards) + """</div></div></section><!-- GOALOS_PROOF_CARDS_V17_END -->"""
def ensure_css(text):
    if 'proof-cards-v17.css' in text: return text
    link = "<link rel='stylesheet' href='assets/proof-cards-v17.css'>"
    return text.replace('</head>', link+'</head>') if '</head>' in text else link+'\n'+text
def inject_index(site,cards):
    p=site/'index.html'
    if not p.exists(): raise SystemExit('site/index.html missing; refusing detached replacement')
    text=ensure_css(p.read_text(encoding='utf-8',errors='replace'))
    sec=section(cards)
    text=re.sub(r'<!-- GOALOS_PROOF_CARDS_V17_START -->.*?<!-- GOALOS_PROOF_CARDS_V17_END -->',sec,text,flags=re.S) if 'GOALOS_PROOF_CARDS_V17_START' in text else (text.replace('</main>',sec+'</main>',1) if '</main>' in text else text.replace('</body>',sec+'</body>',1) if '</body>' in text else text+sec)
    p.write_text(text, encoding='utf-8')
def ul(xs): return '<ul>'+''.join(f'<li>{esc(x)}</li>' for x in xs)+'</ul>'
def card_page(c,cards):
    contracts=' → '.join(esc(x) for x in c['contracts'])
    return f"""<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Proof Card {esc(c['id'])} — {esc(c['title'])}</title><link rel='stylesheet' href='assets/proof-cards-v17.css'></head><body class='proof-page'><header><nav><a href='index.html'>GoalOS AGIALPHA Ascension</a><span><a href='proof-cards.html'>Proof Cards</a> &nbsp; <a href='agialpha-ledger-route.html'>AGIALPHA Route</a> &nbsp; <a href='sovereign-rsi-control-plane.html'>RSI</a></span></nav></header><main class='proof-main'><div class='proof-kicker'>Proof Card {esc(c['id'])} · {esc(c['phase'])}</div><h1>{esc(c['title'])}</h1><p class='proof-lead'>{esc(c['incremental'])}</p><section class='proof-section'><h2>Problem</h2><p>{esc(c['problem'])}</p><h2>Proof mission</h2><p>{esc(c['mission'])}</p></section><section class='proof-section'><h2>Where AGIALPHA becomes useful</h2><p>AGIALPHA coordinates sponsor funding, mission budgets, builder claim bonds, proof submission bonds, reviewer bonds, proof-card registration, credential issuance, reputation-linked routing, reward-vault settlement, treasury routing, and Chronicle memory.</p><table class='proof-table'><tr><th>Function</th><th>Meaning</th></tr><tr><td>Mission posting</td><td>Sponsors fund bounded work.</td></tr><tr><td>Bonds</td><td>Builders and reviewers have skin in the proof process.</td></tr><tr><td>Settlement</td><td>Accepted work creates reward, credential, reputation, and future routing signals.</td></tr></table></section><section class='proof-section'><h2>Smart-contract / registry route</h2><p>{contracts}</p><div class='proof-diagram'><div class='proof-node accent'>GoalOSCommit</div><div class='proof-node'>RunCommitment</div><div class='proof-node'>ProofBundle</div><div class='proof-node'>Review</div><div class='proof-node accent'>Selection</div></div></section><section class='proof-section'><h2>Skills used</h2>{ul(c['skills'])}<h2>Plans used</h2>{ul(c['plans'])}<h2>Goals used</h2>{ul(c['goals'])}</section><section class='proof-section'><h2>RSI upgrade logic</h2><p>{esc(c['rsi'])}</p><p>The efficient RSI loop is: observe weakness → improve artifact → prove change → review evidence → select → grant scoped upgrade rights → chronicle → improve future work.</p></section><section class='proof-section'><h2>Evidence Docket checklist</h2>{ul(['GoalOSCommit','RunCommitment','Task manifest','Baseline','Candidate artifact','ProofBundle','Evaluator report','Reviewer attestation','Cost ledger','Safety ledger','Risk ledger','SelectionCertificate','Rollback plan','Chronicle entry'])}</section><section class='proof-section'><h2>Claim boundary</h2><div class='proof-warning'>This proof card is an experimental public-safe proof template until a live Evidence Docket is completed. It does not claim achieved AGI, achieved superintelligence, guaranteed ROI, legal/tax/security approval, Ethereum mainnet deployment, or Kardashev Type II achievement.</div></section><section class='proof-section'><h2>Proof-card system</h2><div class='proof-cta'><a class='proof-btn primary' href='proof-cards.html'>All proof cards</a></div></section></main><footer class='proof-footer'>GoalOS sets the aim. AGIALPHA coordinates proof-settled work. Evidence Dockets make claims auditable.</footer></body></html>"""
def simple_page(title, body): return f"<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>{esc(title)}</title><link rel='stylesheet' href='assets/proof-cards-v17.css'></head><body class='proof-page'><header><nav><a href='index.html'>GoalOS AGIALPHA Ascension</a><a href='proof-cards.html'>Proof Cards</a></nav></header><main class='proof-main'><div class='proof-kicker'>GoalOS AGIALPHA Ascension</div><h1>{esc(title)}</h1>{body}</main><footer class='proof-footer'>Proof-backed upgrade rights. Evidence before propagation.</footer></body></html>"
def build_pages(site,cards):
    for c in cards: (site/slug(c)).write_text(card_page(c,cards),encoding='utf-8')
    (site/'proof-cards.html').write_text(simple_page('Proof Cards 001-010',"<p class='proof-lead'>Each proof card has its own stable page and is linked from the main website root.</p><div class='proof-card-grid'>"+''.join(tile(c) for c in cards)+"</div>"), encoding='utf-8')
    (site/'agialpha-ledger-route.html').write_text(simple_page('Where AGIALPHA becomes useful',"<section class='proof-section'><p>AGIALPHA coordinates mission posting, builder bonds, proof bonds, reviewer bonds, proof-card actions, credential actions, settlement, reputation-linked routing, reward-vault allocations, treasury routing, and Chronicle memory.</p></section>"),encoding='utf-8')
    (site/'sovereign-rsi-control-plane.html').write_text(simple_page('Sovereign RSI control plane',"<section class='proof-section'><p>RSI is implemented as proof-backed upgrade rights. Future work may reuse an artifact only after evidence, evaluation, reviewer validation, scope control, monitoring, rollback readiness, and Selection Gate approval.</p></section>"),encoding='utf-8')
    (site/'evidence-docket.html').write_text(simple_page('Evidence Docket',"<section class='proof-section'><p>The Evidence Docket records commitments, baselines, ProofBundles, evaluator reports, reviewer attestations, cost and safety ledgers, SelectionCertificates, rollback paths, and Chronicle entries.</p></section>"),encoding='utf-8')
    (site/'season-001.html').write_text(simple_page('Season 001 proof missions',"<section class='proof-section'><p>Season 001 begins with buyer trust, procurement trust, sovereign control, persistent accumulation, value-to-capability reinvestment, enterprise RSI, autoresearch, corporate capability foundry, cyber-sovereign execution, and replayable proof benchmarks.</p></section>"),encoding='utf-8')
    (site/'share.html').write_text(simple_page('Share kit',"<section class='proof-section'><p>GoalOS turns sovereign corporate work into compounding capability: AGIALPHA coordinates proof-settled missions, reviewers validate the evidence, and only proven artifacts earn the right to improve future work.</p></section>"),encoding='utf-8')
def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--site',default='site'); args=ap.parse_args(); site=Path(args.site); cards=load_cards()
    if not (site/'index.html').exists(): raise SystemExit(f'{site}/index.html not found; refusing to create detached replacement site.')
    write_asset(site); build_pages(site,cards); inject_index(site,cards); (site/'evidence').mkdir(exist_ok=True); (site/'evidence'/'proof-card-command-center-report.json').write_text(json.dumps({'status':'integrated','proof_cards':[c['id'] for c in cards]}, indent=2),encoding='utf-8'); print('Integrated Proof Cards 001-010 into canonical main website root.')
if __name__=='__main__': main()
